    const uint32_t H = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(2));
    const uint32_t W = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(3));

    const uint32_t K  = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(0));
    const uint32_t Kh = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(2));
    const uint32_t Kw = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(3));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int *stride_h   = attrs->GetAttrPointer<int>(0);
    const int *stride_w   = attrs->GetAttrPointer<int>(1);
    const int *pad_top    = attrs->GetAttrPointer<int>(2);
    const int *pad_bottom = attrs->GetAttrPointer<int>(3);
    const int *pad_left   = attrs->GetAttrPointer<int>(4);
    const int *pad_right  = attrs->GetAttrPointer<int>(5);
    const int *dil_h      = attrs->GetAttrPointer<int>(6);
    const int *dil_w      = attrs->GetAttrPointer<int>(7);
    const int *groups     = attrs->GetAttrPointer<int>(8);

    // Compute output shape
    const uint32_t effKh = static_cast<uint32_t>((*dil_h) * (static_cast<int>(Kh) - 1) + 1);
    const uint32_t effKw = static_cast<uint32_t>((*dil_w) * (static_cast<int>(Kw) - 1) + 1);

    const uint32_t OH = static_cast<uint32_t>((static_cast<int>(H) + *pad_top + *pad_bottom - static_cast<int>(effKh)) / *stride_h + 1);
